// Updated 2026-03-27: removed deny button; confirm and cancel only.
// Updated 2026-03-27: optional screen anchor to place panel at tooltip.
using System;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Reusable confirmation dialog for the unified shop.
/// Confirm accepts the action (buy / replace); Cancel closes the panel.
/// Provides a focus-trap across active buttons for controller support.
/// </summary>
[DisallowMultipleComponent]
public sealed class ShopConfirmPanel : MonoBehaviour
{
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private TMP_Text messageText;
    [SerializeField] private TMP_Text itemNameText;
    [SerializeField] private TMP_Text itemDescriptionText;
    [SerializeField] private Image itemIconImage;
    [SerializeField] private Button confirmButton;
    [SerializeField] private Button cancelButton;

    private Action _onConfirm;
    private Action _onCancel;

    private RectTransform _panelRect;
    private Canvas _rootCanvas;
    private RectTransform _canvasRect;

    private const float screenEdgePadding = 12f;

    private void Awake()
    {
        if (panelRoot == null)
        {
            panelRoot = gameObject;
        }

        _panelRect = panelRoot.GetComponent<RectTransform>();

        if (confirmButton != null)
        {
            confirmButton.onClick.AddListener(OnConfirmClicked);
        }

        if (cancelButton != null)
        {
            cancelButton.onClick.AddListener(OnCancelClicked);
        }
    }

    private void OnDestroy()
    {
        if (confirmButton != null)
        {
            confirmButton.onClick.RemoveListener(OnConfirmClicked);
        }

        if (cancelButton != null)
        {
            cancelButton.onClick.RemoveListener(OnCancelClicked);
        }
    }

    /// <summary>Shows the panel with the given content and callbacks.</summary>
    /// <param name="anchorScreenPoint">
    /// Optional screen position (pixels) for the panel center; e.g. tooltip center.
    /// </param>
    public void Show(
        string message,
        string itemName,
        string description,
        Sprite icon,
        Action onConfirm,
        Action onCancel,
        Vector2? anchorScreenPoint = null)
    {
        _onConfirm = onConfirm;
        _onCancel = onCancel;

        if (messageText != null)
        {
            messageText.text = message ?? string.Empty;
        }

        if (itemNameText != null)
        {
            itemNameText.text = itemName ?? string.Empty;
        }

        if (itemDescriptionText != null)
        {
            itemDescriptionText.text = description ?? string.Empty;
        }

        if (itemIconImage != null)
        {
            if (icon != null)
            {
                itemIconImage.sprite = icon;
                itemIconImage.enabled = true;
            }
            else
            {
                itemIconImage.sprite = null;
                itemIconImage.enabled = false;
            }
        }

        if (panelRoot != null)
        {
            panelRoot.SetActive(true);
        }

        if (_panelRect != null && !anchorScreenPoint.HasValue)
        {
            _panelRect.anchoredPosition = Vector2.zero;
        }

        Canvas.ForceUpdateCanvases();

        if (_panelRect != null)
        {
            LayoutRebuilder.ForceRebuildLayoutImmediate(_panelRect);
        }

        if (anchorScreenPoint.HasValue)
        {
            PositionPanelAtScreenPoint(anchorScreenPoint.Value);
        }

        SetupFocusTrap();
    }

    public void Hide()
    {
        _onConfirm = null;
        _onCancel = null;

        if (panelRoot != null)
        {
            panelRoot.SetActive(false);
        }
    }

    public bool IsVisible => panelRoot != null && panelRoot.activeSelf;

    private void CacheCanvasIfNeeded()
    {
        if (_canvasRect != null)
        {
            return;
        }

        if (_panelRect == null)
        {
            return;
        }

        _rootCanvas = _panelRect.GetComponentInParent<Canvas>();

        if (_rootCanvas != null)
        {
            _rootCanvas = _rootCanvas.rootCanvas;
            _canvasRect = _rootCanvas.GetComponent<RectTransform>();
        }
    }

    private void PositionPanelAtScreenPoint(Vector2 screenCenter)
    {
        if (_panelRect == null)
        {
            return;
        }

        CacheCanvasIfNeeded();

        if (_canvasRect == null || _rootCanvas == null)
        {
            return;
        }

        Camera cam =
            _rootCanvas.renderMode
                == RenderMode.ScreenSpaceOverlay
                ? null
                : _rootCanvas.worldCamera;

        RectTransformUtility.ScreenPointToLocalPointInRectangle(
            _canvasRect,
            screenCenter,
            cam,
            out Vector2 localPos);

        _panelRect.anchoredPosition = localPos;
        ClampPanelToCanvas();
    }

    private void ClampPanelToCanvas()
    {
        if (_panelRect == null || _canvasRect == null)
        {
            return;
        }

        Vector2 panelSize = _panelRect.rect.size;
        Vector2 canvasSize = _canvasRect.rect.size;
        Vector2 halfCanvas = canvasSize * 0.5f;

        float minX =
            -halfCanvas.x + screenEdgePadding
            + panelSize.x * _panelRect.pivot.x;

        float maxX =
            halfCanvas.x - screenEdgePadding
            - panelSize.x * (1f - _panelRect.pivot.x);

        float minY =
            -halfCanvas.y + screenEdgePadding
            + panelSize.y * _panelRect.pivot.y;

        float maxY =
            halfCanvas.y - screenEdgePadding
            - panelSize.y * (1f - _panelRect.pivot.y);

        Vector2 pos = _panelRect.anchoredPosition;
        pos.x = Mathf.Clamp(pos.x, minX, maxX);
        pos.y = Mathf.Clamp(pos.y, minY, maxY);
        _panelRect.anchoredPosition = pos;
    }

    public void OnConfirmClicked()
    {
        Action cb = _onConfirm;
        ClearCallbacks();
        cb?.Invoke();
    }

    private void OnCancelClicked()
    {
        Action cb = _onCancel;
        ClearCallbacks();
        cb?.Invoke();
    }

    private void ClearCallbacks()
    {
        _onConfirm = null;
        _onCancel = null;
    }

    private void SetupFocusTrap()
    {
        // Collect active buttons for the navigation ring.
        var active = new System.Collections.Generic.List<Button>(2);
        if (confirmButton != null && confirmButton.gameObject.activeInHierarchy) active.Add(confirmButton);
        if (cancelButton != null && cancelButton.gameObject.activeInHierarchy) active.Add(cancelButton);

        if (active.Count < 2)
        {
            return;
        }

        for (int i = 0; i < active.Count; i++)
        {
            Button prev = active[(i - 1 + active.Count) % active.Count];
            Button next = active[(i + 1) % active.Count];

            var nav = active[i].navigation;
            nav.mode = Navigation.Mode.Explicit;
            nav.selectOnLeft = prev;
            nav.selectOnRight = next;
            nav.selectOnUp = prev;
            nav.selectOnDown = next;
            active[i].navigation = nav;
        }

        EventSystem es = EventSystem.current;
        if (es != null && active.Count > 0)
        {
            es.SetSelectedGameObject(active[0].gameObject);
        }
    }

    private void LateUpdate()
    {
        if (panelRoot == null || !panelRoot.activeSelf)
        {
            return;
        }

        EventSystem es = EventSystem.current;
        if (es == null)
        {
            return;
        }

        GameObject selected = es.currentSelectedGameObject;
        if (IsChildOfAnyButton(selected))
        {
            return;
        }

        // Re-select the first available button.
        if (confirmButton != null && confirmButton.gameObject.activeInHierarchy)
        {
            es.SetSelectedGameObject(confirmButton.gameObject);
        }
        else if (cancelButton != null && cancelButton.gameObject.activeInHierarchy)
        {
            es.SetSelectedGameObject(cancelButton.gameObject);
        }
    }

    private bool IsChildOfAnyButton(GameObject selected)
    {
        if (selected == null)
        {
            return false;
        }

        return IsChildOfButton(selected, confirmButton)
            || IsChildOfButton(selected, cancelButton);
    }

    private static bool IsChildOfButton(GameObject selected, Button btn)
    {
        if (btn == null || !btn.gameObject.activeInHierarchy)
        {
            return false;
        }

        return selected == btn.gameObject
            || selected.transform.IsChildOf(btn.transform);
    }
}
